package com.ichi2.anki.preferences

import android.content.Context
import androidx.test.core.app.ApplicationProvider
import com.ichi2.anki.R
import com.ichi2.anki.cardviewer.ViewerCommand
import org.hamcrest.MatcherAssert.assertThat
import org.hamcrest.Matchers.containsInAnyOrder
import org.junit.Test
import org.junit.runner.RunWith
import org.robolectric.RobolectricTestRunner
import org.w3c.dom.Element
import org.w3c.dom.NodeList
import javax.xml.parsers.DocumentBuilderFactory

/**
 * Test to ensure all [ViewerCommand] entries are present in the XML
 * and that commands are not added programmatically.
 */
@RunWith(RobolectricTestRunner::class)
class ControlsSettingsFragmentTest {

    /**
     * Verifies that all ViewerCommand enum values have corresponding
     * ControlPreference entries defined in preferences_controls.xml.
     *
     * This test ensures that commands are defined in XML rather than
     * being added programmatically, which allows them to be organized
     * into categories for better user experience.
     */
    @Test
    fun `all ViewerCommands are present in preferences_controls XML`() {
        val context: Context = ApplicationProvider.getApplicationContext()

        // Get all ViewerCommand preference keys
        val allCommandKeys = ViewerCommand.values().map { it.preferenceKey }.toSet()

        // Parse the XML file to get all ControlPreference keys
        val xmlKeys = getControlPreferenceKeysFromXml(context)

        // Assert that all command keys are present in the XML
        assertThat(
            "All ViewerCommand enum values must have corresponding ControlPreference entries in preferences_controls.xml",
            xmlKeys,
            containsInAnyOrder(*allCommandKeys.toTypedArray())
        )
    }

    /**
     * Parses preferences_controls.xml and extracts all ControlPreference keys.
     */
    private fun getControlPreferenceKeysFromXml(context: Context): Set<String> {
        val keys = mutableSetOf<String>()

        try {
            // Open and parse the XML resource
            val xmlStream = context.resources.getXml(R.xml.preferences_controls)
            val factory = DocumentBuilderFactory.newInstance()
            val builder = factory.newDocumentBuilder()

            // Read the entire XML into a string first
            val xmlString = buildString {
                var eventType = xmlStream.eventType
                while (eventType != org.xmlpull.v1.XmlPullParser.END_DOCUMENT) {
                    when (eventType) {
                        org.xmlpull.v1.XmlPullParser.START_TAG -> {
                            append("<${xmlStream.name}")
                            for (i in 0 until xmlStream.attributeCount) {
                                append(" ${xmlStream.getAttributeName(i)}=\"${xmlStream.getAttributeValue(i)}\"")
                            }
                            append(">")
                        }
                        org.xmlpull.v1.XmlPullParser.END_TAG -> {
                            append("</${xmlStream.name}>")
                        }
                        org.xmlpull.v1.XmlPullParser.TEXT -> {
                            append(xmlStream.text)
                        }
                    }
                    eventType = xmlStream.next()
                }
            }

            // Parse the XML string
            val document = builder.parse(xmlString.byteInputStream())

            // Find all ControlPreference elements
            val controlPreferences = document.getElementsByTagName("com.ichi2.preferences.ControlPreference")
            for (i in 0 until controlPreferences.length) {
                val element = controlPreferences.item(i) as Element
                val key = element.getAttribute("android:key")
                if (key.isNotEmpty()) {
                    keys.add(key)
                }
            }
        } catch (e: Exception) {
            throw AssertionError("Failed to parse preferences_controls.xml", e)
        }

        return keys
    }
}
"}

